DROP TABLE IF EXISTS `jobs`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `jobs` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `firm_id` bigint DEFAULT NULL,
  `title` varchar(255) DEFAULT NULL,
  `location` varchar(100) DEFAULT NULL,
  `type` varchar(50) DEFAULT NULL,
  `department` varchar(255) DEFAULT NULL,
  `work_mode` varchar(100) DEFAULT NULL,
  `experience_level` varchar(100) DEFAULT NULL,
  `openings` int DEFAULT NULL,
  `required_skills` text,
  `benefits` text,
  `required_qualification` text,
  `application_deadline` date DEFAULT NULL,
  `salary` varchar(100) DEFAULT NULL,
  `description` text,
  `hiring_for` varchar(55) DEFAULT NULL,
  `is_active` tinyint(1) DEFAULT '1',
  `status` varchar(25) DEFAULT NULL,
  `created_via` varchar(25) DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `last_applicant_reminder_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `hiring_for` (`hiring_for`) /*!80000 INVISIBLE */,
  KEY `idx_jobs_firm_active` (`firm_id`,`is_active`),
  KEY `idx_jobs_active_status_created` (`is_active`,`status`,`created_at`)
) ENGINE=InnoDB AUTO_INCREMENT=19 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

