INSERT INTO `jobs` VALUES (1,16,'Qualified CA','MUMBAI','qualified','Accounting & Bookkeeping','On-site','1-3 Years',2,'[\"ERP, analytical skills, accounting, auditing, finalisation of books\"]',NULL,'CA qualified, M.com, Bcom',NULL,'60000-85000','Key Responsibilities\n1. Financial Reporting & Accounting\n• Assist in preparation and finalization of financial statements\n• Support month-end and year-end closing activities\n• Prepare schedules, reconciliations, and management reports\n• Ensure compliance with accounting standards and internal policies\n2. Audit Support\n• Coordinate with statutory, internal, and external auditors\n• Prepare audit schedules and supporting documentation\n• Ensure timely submission of information and responses to audit queries\n• Assist in implementation of audit recommendations\n3. ERP Implementation\n• Support implementation and rollout of ERP systems\n• Participate in master data validation and data migration activities\n• Assist in process documentation and system testing\n• Coordinate with internal stakeholders during ERP projects\n4. Compliance & Process Improvement\n• Assist in maintaining accounting controls and procedures\n• Support process optimization initiatives\n• Ensure accurate record-keeping and documentation',NULL,1,'Active',NULL,'2026-06-19 11:41:27','2026-07-09 10:57:59',NULL),(2,16,'Semi-Qualified CA - Finalisation of books( shipping & logistics)','MUMBAI','semi-qualified','Accounting & Bookkeeping','On-site','1-3 Years',2,'[\"Analytical skills, ledger scrutiny, finalisation of accounts, reconciliation, ERP\"]',NULL,'CA inter (cleared any one group), Bcom, Mcom',NULL,'35000-50000','Key Responsibilities\n1. Financial Reporting & Accounting\n• Assist in preparation and finalization of financial statements\n• Support month-end and year-end closing activities\n• Prepare schedules, reconciliations, and management reports\n• Ensure compliance with accounting standards and internal policies\n2. Audit Support\n• Coordinate with statutory, internal, and external auditors\n• Prepare audit schedules and supporting documentation\n• Ensure timely submission of information and responses to audit queries\n• Assist in implementation of audit recommendations\n3. ERP Implementation\n• Support implementation and rollout of ERP systems\n• Participate in master data validation and data migration activities\n• Assist in process documentation and system testing\n• Coordinate with internal stakeholders during ERP projects\n4. Compliance & Process Improvement\n• Assist in maintaining accounting controls and procedures\n• Support process optimization initiatives\n• Ensure accurate record-keeping and documentation','semi-qualified',1,'Active',NULL,'2026-06-19 11:44:31','2026-06-19 11:44:31',NULL),(3,18,'Articleship Trainee - Accounts, GST & Direct Tax','PUNE','articleship','GST & Indirect Tax','On-site','Fresher',2,'[\"GST\",\"Income Tax\",\"Zoho Books\",\"Tally\",\"Accounts\",\"Audit\",\"Compliance\"]',NULL,'CA Inter Cleared.',NULL,'10000','Vacancies for Article Assistants - Opportunity to gain exposure in core areas of professional practice including taxation, accounts, compliance, litigation. \nKey Areas of Exposure- Direct Tax - Indirect Tax - Accounting & Financial Reporting - Regulatory Compliances etc. \nInterested candidates can send their resume on ca.sunil.wadhwani@gmail.com','articleship',1,'Active',NULL,'2026-06-21 14:58:57','2026-06-21 14:58:57',NULL),(4,24,'Articleship Trainee - GST & Indirect Tax','PUNE','articleship','GST & Indirect Tax','On-site','Fresher',2,'[\"Time Management\",\"Communication Skills\",\"Adaptability\",\"Analytical Thinking\",\"Attention to Detail\"]',NULL,'CA Inter both group Cleared',NULL,'12000','Assisted in statutory audits, tax audits, and internal audits of various clients.\nPrepared income tax and GST returns, reconciliations, and compliance reports.\nMaintained accounting records and prepared financial statements.\nCoordinated with clients for documentation and regulatory compliance requirements.\nPerformed financial analysis and prepared management reports.\nEnsured timely completion of assignments while adhering to professional standards.','articleship',1,'Active',NULL,'2026-06-23 11:18:41','2026-06-23 11:18:41',NULL),(5,24,'Qualified CA - Direct Tax','PUNE','qualified','Direct Tax','On-site','3+ Years',1,'[\"GST Notice Handling & Departmental Replies\",\"Client Coordination & Communication\",\"Team Management & Review\",\"Problem-Solving & Analytical Skills\",\"Ownership and Independent Working\",\"GST Advisory\"]',NULL,'Chartered Accountant (CA)',NULL,'70,000-75,000','This role is ideal for someone who have and need to enhance:\n\n✔ Practical exposure in GST compliance & advisory  \n✔ Direct client interaction  \n✔ Ownership and responsibility  \n✔ Long-term growth opportunity  \n\n???? ????????:\n• GST compliance & advisory  \n• GST notices & departmental replies  \n• Client coordination  \n• Team handling & review  \n• Practical problem-solving for businesses','qualified',1,'Active',NULL,'2026-06-23 11:23:23','2026-06-23 11:23:23',NULL),(6,29,'Qualified CA - Senior Audit Associates - Internal Audit','PUNE','qualified','Internal Audit','On-site','1-3 Years',2,'[\"Core process based internal audit experience  perferably with CA Firms\"]',NULL,'Qualified CA',NULL,NULL,'1. Execute internal audit assignments across various industries and business functions.\n2. Perform process walkthroughs, risk assessments, and control testing.\n3. Identify control gaps, process inefficiencies, and compliance issues.\n4. Prepare audit working papers, observations, and audit reports.\n5. Conduct reviews of finance, procurement, inventory, HR, payroll, sales, and operational processes.\n6. Verify compliance with company policies, statutory requirements, and regulatory guidelines.\n7. Follow up on implementation of audit recommendations and corrective actions.\n8. Assist in developing risk-based audit plans and audit programs.\n9. Coordinate with client management for obtaining information and resolving audit queries.\n10. Support special reviews, investigations, and management assignments as required.','qualified',1,'Active',NULL,'2026-06-24 11:38:36','2026-06-24 11:38:36',NULL),(8,26,'Articleship Trainee','MUMBAI','articleship',NULL,'On-site','Fresher',2,'[\"Passion to learn and ready to take up responsibility\"]',NULL,'CA Inter (Both Group cleared)',NULL,'6000-7500','Article will get over all exposure in all fields and hands-on experience.',NULL,1,'Active',NULL,'2026-06-24 13:25:19','2026-06-24 13:37:58',NULL),(9,25,'Articleship Trainee','PUNE','articleship',NULL,'On-site','Fresher',2,'[\"Microsoft Office\",\"Tally\"]',NULL,'CA Inter 1 or Both Groups cleared',NULL,'9000/month - 11000/month','H Mistry & Associates, a premier Chartered Accountancy firm established in 1984, invites applications for Article Assistants at our Pune office.\n\nAbout Us:\nWe provide expert services in Statutory & Tax Audits, Direct & Indirect Taxation, RERA, Accounting, and Compliance, serving domestic and international clients for over four decades.\n\n? Exposure Areas:\n* Statutory & Tax Audits\n* Internal Audits\n* International Taxation\n* ITR & GST Filings\n* TDS Compliance\n* Bookkeeping & Accounting\n* Income Tax & GST Assessments\n\n? Stipend:\n* 1st Year – ₹9,000 per month\n* 2nd Year – Minimum ₹11,000 per month (also performance-based increments)\n\nInterested candidates may email their CV to: harshal@cahmistry.com\nhmistryandassociates@gmail.com\n\n? Website: https://cahmistry.com/','articleship',1,'Active',NULL,'2026-06-24 15:59:38','2026-06-24 15:59:38',NULL),(10,2,'Articleship Trainee - Internal Audit','PUNE','articleship','Internal Audit','On-site','Fresher',1,'[\"Willingness to learn\"]',NULL,'CA Inter both groups cleared. (No limits on attempt)',NULL,NULL,'Assist in planning, executing, and concluding internal audit engagements across various business cycles (Procure to Pay, Order to Cash, Inventory, HR, etc.).\nIdentify control gaps, operational inefficiencies, and areas of revenue leakage.\nPerform risk assessments and ensure compliance with statutory laws and corporate policies.\nDraft detailed audit observations and assist in preparing comprehensive Internal Audit Reports for management.\nConduct physical verification of inventory and fixed assets.\nFollow up with client process owners on the implementation of audit recommendations.','articleship',1,'Active',NULL,'2026-06-24 17:10:10','2026-06-24 17:10:10',NULL),(11,9,'Articleship Trainee','PUNE','articleship',NULL,'On-site','Fresher',5,NULL,NULL,'CA Inter Both group cleared and IT/OC completed',NULL,'10000','Overall exposure in Statutory, Internal Audit, Litigation, Income Tax Compliances, etc.','articleship',1,'Active',NULL,'2026-06-25 10:17:19','2026-07-09 09:00:03','2026-07-09 09:00:03'),(12,40,'Articleship Trainee - GST & Indirect Tax','HYDERABAD','articleship','GST & Indirect Tax','On-site','Fresher',2,NULL,NULL,'CA Inter passed',NULL,'15000','We are looking for motivated and dedicated CA Article Assistants who are eager to gain practical exposure across various areas of accounting, taxation, auditing, and compliance. This role offers an excellent opportunity to develop professional skills while working with experienced Chartered Accountants and a diverse client base.\n\nKey Responsibilities\nAssist in statutory audits, tax audits, and internal audits.\nPrepare and file Income Tax Returns (ITR), GST returns, TDS returns, and other statutory compliances.\nMaintain books of accounts and prepare financial statements.\nConduct bank reconciliations and account analysis.\nSupport in ROC and MCA compliance work.\nAssist in tax planning, assessments, and representation before tax authorities.\nPrepare reports, working papers, and documentation for audits and client assignments.\nCoordinate with clients to collect financial information and resolve compliance-related queries.\nStay updated with changes in tax laws, accounting standards, and regulatory requirements.','articleship',1,'Active',NULL,'2026-06-27 17:34:14','2026-06-27 17:34:14',NULL),(13,16,'Articleship Trainee','MUMBAI','articleship',NULL,'On-site','0-1 Years',1,'[\"audit\",\"taxation\",\"bookeeping\",\"gst\",\"accounting\"]',NULL,'CA inter',NULL,'10000-15000','We are looking for motivated CA Article Assistants to join our Chartered Accountancy firm. The selected candidates will gain practical exposure in Statutory Audit, Internal Audit, GST, Income Tax, ROC Compliances, Bank Audits, and Financial Reporting across diverse industries.\n\nKey Responsibilities:\n\nAssist in statutory, internal, and tax audits.\nPrepare and review financial statements and audit working papers.\nHandle GST, Income Tax, TDS, and ROC compliances.\nSupport in accounting, reconciliations, and client coordination.\nConduct research on accounting, taxation, and regulatory matters.\n\nEligibility:\n\nCleared CA Intermediate (Both Groups/Eligible as per ICAI norms).\nGood knowledge of Accounting, GST, and Income Tax.\nProficient in MS Excel and MS Office.\nStrong analytical, communication, and interpersonal skills.\n\nWhat We Offer:\n\nExposure to diverse industries and challenging assignments.\nHands-on learning under experienced Chartered Accountants.\nProfessional growth in audit, taxation, and advisory services.\nStipend as per firm policy and ICAI guidelines.','articleship',1,'Active',NULL,'2026-06-29 15:23:51','2026-07-09 09:00:03','2026-07-09 09:00:03'),(14,29,'Articleship Trainee - Direct Tax / Indirect Tax','PUNE','articleship','Direct Tax','On-site','Fresher',3,NULL,NULL,'CA Inter both groups',NULL,'7-8K','Direct Tax - Corporate & Individual ITR, Scrutiny Assessments, TDS Compliance, Lower TDS Applications, Start up Compliances, Certification and advisory work\nIndirect Tax - GST Advisory Services, Monthly / Quarterly GST Returns, GST Departmental Audits & Assessments, GST Refund claims, Drafting and Responding to notices.',NULL,1,'Active',NULL,'2026-06-30 11:02:37','2026-07-09 09:00:03','2026-07-09 09:00:03'),(15,45,'Articleship Trainee - Statutory Audit','PUNE','articleship','Statutory Audit','On-site','Fresher',2,NULL,NULL,'CA Inter Both Groups Cleared',NULL,'8000-10000','? We Are Hiring – Articleship Vacancies at M/s. SKPN & Associates LLP, Chartered Accountants, Pune\n\nSKPN & Associates LLP is a reputed Chartered Accountants firm offering diverse professional services across multiple domains:\n\n? Income Tax Consultancy, Audits & Return Filing\n? Goods & Services Tax (GST) – Advisory, Filings & Audits\n? Accounting & Bookkeeping\n? Statutory Audits & ROC Compliances\n? International Taxation & Transfer Pricing\n? Business Valuation, M&A, Due Diligence, RERA & FEMA\n? Other Regulatory Registrations & Consultancy\n\nWe are currently looking for dedicated and career-oriented CA Article Trainees.  At SKPN, you will gain rich and well-rounded exposure across multiple domains, along with an opportunity to specialize in areas aligned with your interests.\n\nChinchwad Office:\nOffice No. 607, 6th Floor, KP Square,\nOpp. DoubleTree by Hilton Hotel,\nChinchwad, Pune – 411019','articleship',1,'Active',NULL,'2026-06-30 13:14:10','2026-07-09 09:00:03','2026-07-09 09:00:03'),(16,45,'Articleship Trainee - GST & Indirect Tax','PUNE','articleship','GST & Indirect Tax','On-site','Fresher',1,NULL,NULL,'CA Inter Both Groups cleared',NULL,'8000-10000','? We Are Hiring – Articleship Vacancies at M/s. SKPN & Associates LLP, Chartered Accountants, Pune\n\nSKPN & Associates LLP is a reputed Chartered Accountants firm offering diverse professional services across multiple domains:\n\n? Income Tax Consultancy, Audits & Return Filing\n? Goods & Services Tax (GST) – Advisory, Filings & Audits\n? Accounting & Bookkeeping\n? Statutory Audits & ROC Compliances\n? International Taxation & Transfer Pricing\n? Business Valuation, M&A, Due Diligence, RERA & FEMA\n? Other Regulatory Registrations & Consultancy\n\nWe are currently looking for dedicated and career-oriented CA Article Trainees.At SKPN, you will gain rich and well-rounded exposure across multiple domains, along with an opportunity to specialize in areas aligned with your interests.','articleship',1,'Active',NULL,'2026-06-30 13:15:22','2026-06-30 13:15:22',NULL),(17,42,'Articleship trainee','PUNE','articleship',NULL,'On-site','Fresher',4,NULL,NULL,'CA-Intermediate both group cleared ,completion of ICITSS as per  ICAI norms,',NULL,'9000','We are looking for dedicated and enthusiastic CA Articles to join our team. Our articleship program is designed to provide a strong foundation of practical knowledge, professional discipline, and industry exposure. This journey will help you develop not only technical expertise in audit, taxation, compliance, and advisory, but also the professionalism, attitude, and work ethic required to excel in the corporate world. If you are eager to learn, adaptable to challenges, and committed to continuous growth, this opportunity will help shape you into a confident and skilled professional.','articleship',1,'Active',NULL,'2026-07-01 12:13:18','2026-07-09 09:00:03','2026-07-09 09:00:03'),(18,48,'Articleship Trainee - Indirect Tax (GST & Customs)','PUNE','articleship','GST & Indirect Tax','On-site','Fresher',7,NULL,NULL,'Inter Both Group Passed',NULL,'10,000/month 1st year  to  14,000/month 2nd year','Key Areas of Exposure:\n\nAdvisory & Compliance\nLitigation, Notices & Appeals\nGST Health Checks & Reviews\nInvestigations, Search & Raids\nAudit Support & GST Consulting\nAdvisory & Opinions\nReturns, Refunds & Compliance\nClient Meetings with CFOs, Promoters & Business Owners\n\nWhat You\'ll Gain:\n\nOne-on-One Mentorship\nReal Client Interaction\nExposure to AI Tools & Modern Technology\nStrong drafting, research, Excel & communication skills\nFast-growth learning environment with ownership','articleship',1,'Active',NULL,'2026-07-02 16:41:32','2026-07-09 09:00:03','2026-07-09 09:00:03');
